import React, { useMemo } from 'react';
import { QRCodeSVG, QRCodeCanvas } from 'qrcode.react';
import { generateVietQR, VietQROptions } from '@viet-qr/core';

export interface VietQRProps extends VietQROptions {
  /**
   * Định dạng xuất mã QR
   * - svg: Độ phân giải vô hạn, rất sắc nét (mặc định)
   * - canvas: Trả về thẻ <canvas>, hỗ trợ tốt việc Download làm ảnh tĩnh.
   */
  renderAs?: 'svg' | 'canvas';
  /**
   * Kích thước của mã QR (pixel). Mặc định là 256.
   */
  size?: number;
  /**
   * Màu nền mã QR. Mặc định '#FFFFFF'
   */
  bgColor?: string;
  /**
   * Màu của các chấm QR. Mặc định '#000000'
   */
  fgColor?: string;
  /**
   * Mức độ tự sửa lỗi. 'L' | 'M' | 'Q' | 'H'.
   * Nếu bạn chèn Logo bằng imageSettings, nên để 'Q' hoặc 'H'. Mặc định 'Q'.
   */
  level?: 'L' | 'M' | 'Q' | 'H';
  /**
   * Kích hoạt vùng biên trắng bao quanh QR.
   */
  includeMargin?: boolean;
  /**
   * Cấu hình chèn Logo vào giữa mã QR
   */
  imageSettings?: {
    src: string;
    height: number;
    width: number;
    excavate: boolean; // Khoét lỗ giữa QR để chèn ảnh không bị đè lên pattern
    x?: number;
    y?: number;
  };
  className?: string;
  style?: React.CSSProperties;
}

export const VietQR: React.FC<VietQRProps> = (props) => {
  const {
    bankId,
    accountNo,
    accountName,
    amount,
    content,
    renderAs = 'svg',
    size = 256,
    bgColor = '#FFFFFF',
    fgColor = '#000000',
    level = 'Q',
    includeMargin = false,
    imageSettings,
    className,
    style,
  } = props;

  // Sử dụng useMemo để tránh việc sinh lại chuỗi mỗi khi component re-render không cần thiết
  const payload = useMemo(() => {
    try {
      return generateVietQR({ bankId, accountNo, accountName, amount, content });
    } catch (e) {
      console.error('[@viet-qr/react] Generation Error:', e);
      return '';
    }
  }, [bankId, accountNo, accountName, amount, content]);

  if (!payload) {
    // Trả về UI trống nếu dữ liệu đầu vào không hợp lệ
    return null;
  }

  const qrProps = {
    value: payload,
    size,
    bgColor,
    fgColor,
    level,
    includeMargin,
    imageSettings,
    className,
    style,
  };

  return renderAs === 'canvas' ? (
    <QRCodeCanvas {...qrProps} />
  ) : (
    <QRCodeSVG {...qrProps} />
  );
};
